import React, { useState, useEffect } from 'react';

const LabTests = ({ userRole }) => {
  const [labTests, setLabTests] = useState([]);
  const [patients, setPatients] = useState([]);
  const [testTypes, setTestTypes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showResultsModal, setShowResultsModal] = useState(false);
  const [selectedTest, setSelectedTest] = useState(null);
  const [stats, setStats] = useState({});
  const [formData, setFormData] = useState({
    patient_id: '',
    test_type: '',
    test_name: '',
    notes: ''
  });
  const [resultsData, setResultsData] = useState({
    status: 'pending',
    results: '',
    normal_range: '',
    notes: ''
  });

  useEffect(() => {
    fetchLabTests();
    fetchStats();
    fetchTestTypes();
    if (userRole === 'doctor' || userRole === 'receptionist') {
      fetchPatients();
    }
  }, []);

  const fetchLabTests = async () => {
    try {
      let url = 'http://localhost:5000/api/lab-tests/today';

      if (userRole === 'lab_technician') {
        url = 'http://localhost:5000/api/lab-tests/pending';
      }

      const response = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setLabTests(data);
    } catch (error) {
      console.error('Error fetching lab tests:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchPatients = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/patients', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setPatients(data.patients || []);
    } catch (error) {
      console.error('Error fetching patients:', error);
    }
  };

  const fetchTestTypes = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/lab-tests/test-types', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setTestTypes(data);
    } catch (error) {
      console.error('Error fetching test types:', error);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/lab-tests/stats', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setStats(data);
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:5000/api/lab-tests', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(formData)
      });

      if (response.ok) {
        setShowModal(false);
        fetchLabTests();
        fetchStats();
        setFormData({
          patient_id: '',
          test_type: '',
          test_name: '',
          notes: ''
        });
      }
    } catch (error) {
      console.error('Error creating lab test:', error);
    }
  };

  const handleResultsSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch(`http://localhost:5000/api/lab-tests/${selectedTest.id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(resultsData)
      });

      if (response.ok) {
        setShowResultsModal(false);
        fetchLabTests();
        fetchStats();
        setSelectedTest(null);
        setResultsData({
          status: 'pending',
          results: '',
          normal_range: '',
          notes: ''
        });
      }
    } catch (error) {
      console.error('Error updating lab test:', error);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'in_progress': return 'bg-blue-100 text-blue-800';
      case 'completed': return 'bg-green-100 text-green-800';
      case 'cancelled': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'pending': return '⏳';
      case 'in_progress': return '🔬';
      case 'completed': return '✅';
      case 'cancelled': return '❌';
      default: return '📋';
    }
  };

  const handleTestTypeSelect = (testType, testName) => {
    setFormData({
      ...formData,
      test_type: testType,
      test_name: testName
    });
  };

  if (loading) {
    return <div className="flex justify-center items-center h-64">Loading lab tests...</div>;
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">
          {userRole === 'lab_technician' ? 'Lab Test Processing' : 'Lab Tests'}
        </h2>
        {userRole === 'doctor' && (
          <button
            onClick={() => setShowModal(true)}
            className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600 transition-colors"
          >
            Request Lab Test
          </button>
        )}
      </div>

      {/* Lab Test Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-white rounded-lg shadow-md p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-600">Total Tests</p>
              <p className="text-2xl font-bold text-gray-800">{stats.total_tests || 0}</p>
            </div>
            <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white">
              🔬
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-600">Pending</p>
              <p className="text-2xl font-bold text-yellow-600">{stats.pending || 0}</p>
            </div>
            <div className="w-10 h-10 bg-yellow-500 rounded-full flex items-center justify-center text-white">
              ⏳
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-600">In Progress</p>
              <p className="text-2xl font-bold text-blue-600">{stats.in_progress || 0}</p>
            </div>
            <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white">
              🔬
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-600">Completed</p>
              <p className="text-2xl font-bold text-green-600">{stats.completed || 0}</p>
            </div>
            <div className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center text-white">
              ✅
            </div>
          </div>
        </div>
      </div>

      {/* Lab Tests Table */}
      <div className="bg-white rounded-lg shadow-md overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Requested
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Patient
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Test Type
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Test Name
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Doctor
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {labTests.map((test) => (
                <tr key={test.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {new Date(test.requested_at).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div>
                      <div className="text-sm font-medium text-gray-900">
                        {test.patient_first_name} {test.patient_last_name}
                      </div>
                      <div className="text-sm text-gray-500">{test.patient_id}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {test.test_type}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {test.test_name}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusColor(test.status)}`}>
                      {getStatusIcon(test.status)} {test.status.replace('_', ' ')}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {test.doctor_first_name && test.doctor_last_name 
                      ? `Dr. ${test.doctor_first_name} ${test.doctor_last_name}`
                      : 'Unknown'
                    }
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex space-x-2">
                      {userRole === 'lab_technician' && test.status === 'pending' && (
                        <button
                          onClick={() => {
                            setSelectedTest(test);
                            setResultsData({
                              status: 'in_progress',
                              results: '',
                              normal_range: '',
                              notes: ''
                            });
                            setShowResultsModal(true);
                          }}
                          className="text-blue-600 hover:text-blue-900"
                        >
                          Process
                        </button>
                      )}
                      {userRole === 'lab_technician' && test.status === 'in_progress' && (
                        <button
                          onClick={() => {
                            setSelectedTest(test);
                            setResultsData({
                              status: 'completed',
                              results: test.results || '',
                              normal_range: test.normal_range || '',
                              notes: test.notes || ''
                            });
                            setShowResultsModal(true);
                          }}
                          className="text-green-600 hover:text-green-900"
                        >
                          Complete
                        </button>
                      )}
                      {userRole === 'doctor' && test.status === 'completed' && (
                        <button
                          onClick={() => {
                            setSelectedTest(test);
                            setResultsData({
                              status: test.status,
                              results: test.results || '',
                              normal_range: test.normal_range || '',
                              notes: test.notes || ''
                            });
                            setShowResultsModal(true);
                          }}
                          className="text-blue-600 hover:text-blue-900"
                        >
                          View Results
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* New Lab Test Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-screen overflow-y-auto">
            <h3 className="text-lg font-semibold mb-4">Request Lab Test</h3>
            <form onSubmit={handleSubmit}>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Patient
                  </label>
                  <select
                    value={formData.patient_id}
                    onChange={(e) => setFormData({...formData, patient_id: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                  >
                    <option value="">Select Patient</option>
                    {patients.map((patient) => (
                      <option key={patient.id} value={patient.id}>
                        {patient.first_name} {patient.last_name} ({patient.patient_id})
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Test Type
                  </label>
                  <select
                    value={formData.test_type}
                    onChange={(e) => setFormData({...formData, test_type: e.target.value, test_name: ''})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                  >
                    <option value="">Select Test Type</option>
                    <option value="hematology">Hematology</option>
                    <option value="chemistry">Chemistry</option>
                    <option value="microbiology">Microbiology</option>
                    <option value="immunology">Immunology</option>
                    <option value="urinalysis">Urinalysis</option>
                    <option value="parasitology">Parasitology</option>
                    <option value="hormone">Hormone</option>
                    <option value="cardiac">Cardiac</option>
                    <option value="toxicology">Toxicology</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Test Name
                  </label>
                  <select
                    value={formData.test_name}
                    onChange={(e) => setFormData({...formData, test_name: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                    disabled={!formData.test_type}
                  >
                    <option value="">Select Test</option>
                    {testTypes
                      .filter(test => test.type === formData.test_type)
                      .map((test, index) => (
                        <option key={index} value={test.name}>
                          {test.name}
                        </option>
                      ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Notes
                  </label>
                  <textarea
                    value={formData.notes}
                    onChange={(e) => setFormData({...formData, notes: e.target.value})}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows="3"
                    placeholder="Additional notes about the test request..."
                  />
                </div>
              </div>

              <div className="flex justify-end space-x-3 mt-6">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="px-4 py-2 text-gray-700 border border-gray-300 rounded-md hover:bg-gray-50"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600"
                >
                  Request Test
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Results/Processing Modal */}
      {showResultsModal && selectedTest && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-screen overflow-y-auto">
            <h3 className="text-lg font-semibold mb-4">
              {userRole === 'lab_technician' ? 'Process Lab Test' : 'Lab Test Results'}
            </h3>
            <div className="mb-4">
              <div className="text-sm text-gray-600">
                <p><strong>Patient:</strong> {selectedTest.patient_first_name} {selectedTest.patient_last_name}</p>
                <p><strong>Test:</strong> {selectedTest.test_name}</p>
                <p><strong>Type:</strong> {selectedTest.test_type}</p>
                <p><strong>Requested:</strong> {new Date(selectedTest.requested_at).toLocaleDateString()}</p>
              </div>
            </div>
            {userRole === 'doctor' && selectedTest.status === 'completed' ? (
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Results
                  </label>
                  <div className="p-3 bg-gray-50 rounded-md">
                    <pre className="whitespace-pre-wrap text-sm">{selectedTest.results || 'No results available'}</pre>
                  </div>
                </div>
                {selectedTest.normal_range && (
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Normal Range
                    </label>
                    <div className="p-3 bg-blue-50 rounded-md">
                      <pre className="whitespace-pre-wrap text-sm">{selectedTest.normal_range}</pre>
                    </div>
                  </div>
                )}
                {selectedTest.notes && (
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Notes
                    </label>
                    <div className="p-3 bg-gray-50 rounded-md">
                      <pre className="whitespace-pre-wrap text-sm">{selectedTest.notes}</pre>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <form onSubmit={handleResultsSubmit}>
                <div className="space-y-4">
                  {userRole === 'lab_technician' && (
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        Status
                      </label>
                      <select
                        value={resultsData.status}
                        onChange={(e) => setResultsData({...resultsData, status: e.target.value})}
                        className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                      >
                        <option value="pending">Pending</option>
                        <option value="in_progress">In Progress</option>
                        <option value="completed">Completed</option>
                        <option value="cancelled">Cancelled</option>
                      </select>
                    </div>
                  )}

                  {resultsData.status === 'completed' && (
                    <>
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Results
                        </label>
                        <textarea
                          value={resultsData.results}
                          onChange={(e) => setResultsData({...resultsData, results: e.target.value})}
                          className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                          rows="6"
                          placeholder="Enter test results..."
                          required
                        />
                      </div>

                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Normal Range
                        </label>
                        <textarea
                          value={resultsData.normal_range}
                          onChange={(e) => setResultsData({...resultsData, normal_range: e.target.value})}
                          className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                          rows="3"
                          placeholder="Enter normal reference range..."
                        />
                      </div>
                    </>
                  )}

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Notes
                    </label>
                    <textarea
                      value={resultsData.notes}
                      onChange={(e) => setResultsData({...resultsData, notes: e.target.value})}
                      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                      rows="3"
                      placeholder="Additional notes..."
                    />
                  </div>
                </div>

                <div className="flex justify-end space-x-3 mt-6">
                  <button
                    type="button"
                    onClick={() => {
                      setShowResultsModal(false);
                      setSelectedTest(null);
                      setResultsData({
                        status: 'pending',
                        results: '',
                        normal_range: '',
                        notes: ''
                      });
                    }}
                    className="px-4 py-2 text-gray-700 border border-gray-300 rounded-md hover:bg-gray-50"
                  >
                    Cancel
                  </button>
                  {userRole === 'lab_technician' && (
                    <button
                      type="submit"
                      className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600"
                    >
                      {resultsData.status === 'completed' ? 'Complete Test' : 'Update Status'}
                    </button>
                  )}
                </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default LabTests;
